:host ::ng-deep {
  .fc {
    height: 100% !important;
    border: none;

    // Header của lịch (Các ngày trong tuần)
    .fc-col-header-cell {
      background: #ffffff;
      padding: 15px 0 !important;
      border: none;
      border-bottom: 1px solid #edf2f7;
      
      .fc-col-header-cell-cushion {
        color: #4a5568;
        font-weight: 700;
        font-size: 14px;
        text-decoration: none !important;
      }
    }

    // Các đường kẻ lưới
    .fc-timegrid-slots .fc-timegrid-slot {
      height: 50px !important; // Độ rộng dòng vừa phải
      border-bottom: 1px solid #f7fafc !important;
    }

    .fc-timegrid-slot-label-cushion {
      font-size: 11px;
      font-weight: 600;
      color: #a0aec0;
    }

    .fc-scrollgrid { border: none !important; }

    // Thanh cuộn
    .fc-scroller {
      &::-webkit-scrollbar { width: 6px; }
      &::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
    }
  }

  // MODERN EVENT CARD STYLE
  .event-card-container {
    height: 100%;
    width: 100%;
    padding: 6px;
    border-radius: 12px;
    border-left: 5px solid;
    display: flex;
    flex-direction: column;
    gap: 2px;
    position: relative;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
    transition: transform 0.2s;

    &:hover { transform: scale(1.02); z-index: 50; }

    &.green {
      background: #f0fdf4;
      border-color: #00b14f;
      .event-time { color: #166534; }
      .event-badge { background: #dcfce7; color: #166534; }
    }

    &.blue {
      background: #eff6ff;
      border-color: #3b82f6;
      .event-time { color: #1e40af; }
      .event-badge { background: #dbeafe; color: #1e40af; }
    }

    .event-time { font-size: 10px; font-weight: 800; }
    .event-title { 
      font-size: 12px; 
      font-weight: 700; 
      color: #1a202c;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
    .event-user { font-size: 10px; color: #718096; font-style: italic; }
    
    .event-badge {
      position: absolute;
      bottom: 4px;
      right: 4px;
      padding: 2px 6px;
      border-radius: 6px;
      font-size: 8px;
      font-weight: 900;
      text-transform: uppercase;
    }
  }

  // Khắc phục item quá ngắn bị mất chữ
  .fc-timegrid-event-harness {
    min-height: 55px !important; 
    margin-bottom: 2px !important;
  }
}
